package controller;
import koneksi.Koneksi;import java.io.*;import java.sql.*;import java.time.LocalDate;import java.util.*;import com.itextpdf.kernel.pdf.*;import com.itextpdf.layout.*;import com.itextpdf.layout.element.*;import org.apache.poi.ss.usermodel.*;import org.apache.poi.xssf.usermodel.XSSFWorkbook;
public class LaporanController{public List<Object[]> bukuKas(LocalDate a,LocalDate b)throws SQLException{List<Object[]>l=new ArrayList<>();String sql="SELECT tanggal,keterangan,nominal,0 kredit FROM pemasukan WHERE tanggal BETWEEN ? AND ? UNION ALL SELECT tanggal,keterangan,0 debit,nominal FROM pengeluaran WHERE tanggal BETWEEN ? AND ? ORDER BY tanggal";try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql)){ps.setDate(1,java.sql.Date.valueOf(a));ps.setDate(2,java.sql.Date.valueOf(b));ps.setDate(3,java.sql.Date.valueOf(a));ps.setDate(4,java.sql.Date.valueOf(b));try(ResultSet r=ps.executeQuery()){while(r.next())l.add(new Object[]{r.getDate(1),r.getString(2),r.getDouble(3),r.getDouble(4)});}}return l;}public List<Object[]> tunggakanSpp(int bulan,int tahun)throws SQLException{List<Object[]>l=new ArrayList<>();String sql="SELECT s.nis,s.nama_siswa,k.nama_kelas,st.nominal FROM spp_tagihan st JOIN siswa s ON s.id_siswa=st.id_siswa LEFT JOIN kelas k ON k.id_kelas=s.id_kelas WHERE st.bulan=? AND st.tahun=? AND st.status='BELUM_LUNAS'";try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql)){ps.setInt(1,bulan);ps.setInt(2,tahun);try(ResultSet r=ps.executeQuery()){while(r.next())l.add(new Object[]{r.getString(1),r.getString(2),r.getString(3),r.getDouble(4)});}}return l;}public void exportPdf(File f,List<Object[]> rows,String judul)throws IOException{try(PdfWriter w=new PdfWriter(f);PdfDocument pdf=new PdfDocument(w);Document d=new Document(pdf)){d.add(new Paragraph(judul).setBold().setFontSize(18));for(Object[] r:rows)d.add(new Paragraph(Arrays.toString(r)));}}public void exportExcel(File f,List<Object[]> rows,String sheet)throws IOException{try(Workbook wb=new XSSFWorkbook();FileOutputStream out=new FileOutputStream(f)){Sheet s=wb.createSheet(sheet);int i=0;for(Object[] row:rows){Row rr=s.createRow(i++);for(int c=0;c<row.length;c++)rr.createCell(c).setCellValue(String.valueOf(row[c]));}wb.write(out);}}}
